    "occupation_median.plot(kind='bar', figsize=(12, 5))\n",
    "plt.title('Median GAD-7 Score by Occupation')\n",
    "plt.ylabel('Median Score')\n",
    "plt.xlabel('Occupation')\n",
    "plt.xticks(rotation=45, ha='right')\n",
    "plt.show()\n",
    "\n",
    "# Boxplot\n",
    "fig, ax = plt.subplots(figsize=(14, 6))\n",
    "df.boxplot(column='score', by='occupation_label', ax=ax)\n",
    "ax.set_title('GAD-7 Score Distribution by Occupation')\n",
    "ax.set_xlabel('Occupation')\n",
    "ax.set_ylabel('Score')\n",
    "plt.suptitle('')\n",
    "plt.xticks(rotation=45, ha='right')\n",
    "plt.show()\n",
    "\n",
    "# Kruskal-Wallis test\n",
    "groups = [\n",
    "    'Tech industry',\n",
    "    'Finance',\n",
    "    'Healthcare',\n",
    "    'Media',\n",
    "    'Government',\n",
    "    'Teacher',\n",
    "    'Advertisement',\n",
    "    'Homemaker',\n",
    "    'Entrepreneur',\n",
    "    'Service',\n",
    "    'Worker',\n",
    "    'Farmer',\n",
    "    'Student'\n",
    "]\n",
    "\n",
    "stat, p_value = kruskal(*score_groups)\n",
    "\n",
    "print('Kruskal-Wallis statistic:', stat)\n",
    "print('p-value:', p_value)\n",
    "\n",
    "## Result\n",
    "## GAD-7 scores differ significantly across occupation groups.\n",
    "## The Kruskal-Wallis test indicates a statistically significant difference\n",
    "## in anxiety scores among the occupation categories (H = 755.87, p < 0.001).\n",
    "\n",
    "## Interpretation\n",
    "## This suggests that anxiety symptoms are not evenly distributed across occupations.\n",
    "## In this dataset, students, advertisement workers, and homemakers tend to report\n",
    "## relatively higher median GAD-7 scores, while healthcare, media, government,\n",
    "## and entrepreneur groups generally show lower median anxiety scores."
